def common_prefix(strings, n):
    min_len = min(len(s) for s in strings)
    prefix = ''
    for i in range(min_len):
        current_char = strings[0][i]
        for s in strings:
            if s[i] != current_char:
                return prefix
        prefix += current_char
    return prefix
